INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '4cd8aa0c-2c37-4692-8d27-978f52b78d8b',
  '00000000-0000-0000-0000-000000000001',
  $escape$fastify + Drizzle ORM — Killing N+1 Without Losing Type Safety$escape$,
  $escape$Fastify pairs naturally with lightweight query builders like Drizzle or Kysely over heavyweight ORMs like Sequelize. Heavy ORMs obscure SQL, make N+1 queries trivial to introduce, and bloat cold-start time — a real problem when Fastify's speed is your selling point.

With Drizzle, register a single db instance via `fastify.decorate` so every route shares one connection pool. For N+1, never fetch relations in a loop. Instead, use Drizzle's `with` clause (relational queries) or a manual JOIN — one query, full type inference. Drizzle's `db.query.posts.findMany({ with: { author: true } })` compiles to a single SQL JOIN, not N round trips.

For migrations, run `drizzle-kit push` (dev) or `drizzle-kit generate` + `migrate` (prod) before your Fastify server starts. Wire this into your `onReady` hook or a pre-start script in your Dockerfile — never inside a route handler. Schema drift between your TypeScript types and actual DB columns becomes a compile-time error, not a 3am incident.$escape$,
  $escape$import Fastify from 'fastify';
import { drizzle } from 'drizzle-orm/node-postgres';
import { Pool } from 'pg';
import * as schema from './schema';

const app = Fastify();
const pool = new Pool({ connectionString: process.env.DATABASE_URL });
const db = drizzle(pool, { schema });

app.decorate('db', db);

app.get('/posts', async (req, reply) => {
  // One JOIN query — no N+1
  const posts = await req.server.db.query.posts.findMany({
    with: { author: true },
  });
  return posts;
});

await app.listen({ port: 3000 });$escape$,
