INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'b002093a-cba5-4695-8e52-ff3759816f95',
  '00000000-0000-0000-0000-000000000001',
  $escape$Fastify Testing — Unit vs Integration, Mocking HTTP, and Test Database Strategy$escape$,
  $escape$Fastify's built-in `inject()` method eliminates the need for a real HTTP server in integration tests — call `app.inject({ method: 'GET', url: '/users/1' })` and get a full response object including status, headers, and payload. This makes integration tests fast without sacrificing coverage of your route handlers, hooks, and serialization schemas.

For unit tests, isolate business logic by extracting it from route handlers and testing it directly. Avoid testing Fastify internals — test your own code.

For mocking downstream HTTP calls, use `@fastify/undici` or wrap `fetch`/`axios` behind a service interface, then swap it with a mock via Fastify's `decorate()` in test setup. Register the mock before calling `app.ready()`.

For database strategy, use a real PostgreSQL instance (Docker) with transaction rollbacks per test — wrap each test in `BEGIN`/`ROLLBACK` using your pool directly. Register the pool via `fastify.decorate('db', pool)` so the same interface works in tests and production. Never mock your ORM — schema mismatches will bite you in production.$escape$,
  $escape$import Fastify from 'fastify';
import { buildApp } from '../src/app';

let app: ReturnType<typeof Fastify>;

beforeEach(async () => {
  app = buildApp();
  app.decorate('db', mockPool); // swap real pool with mock
  await app.ready();
});

afterEach(() => app.close());

it('GET /users/1 returns user', async () => {
  const res = await app.inject({ method: 'GET', url: '/users/1' });
  expect(res.statusCode).toBe(200);
  expect(res.json()).toMatchObject({ id: 1 });
});$escape$,
