INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '53edcaed-dda2-481c-ae38-1fcf94f24e00',
  '00000000-0000-0000-0000-000000000001',
  $escape$Fastify JWT Auth — Validation, Hooks, and Route-Level Guards$escape$,
  $escape$Fastify's `@fastify/jwt` plugin wires JWT validation directly into the request lifecycle via decorators and hooks. After registering the plugin with your secret, `fastify.authenticate` becomes a reusable `preHandler` hook you attach per-route or at the scope level.

The plugin decorates `request` with `request.jwtVerify()`, which validates the token from the `Authorization: Bearer` header, verifies the signature, checks `exp`, and populates `request.user` with the decoded payload — all in one call. If verification fails, it throws a 401 automatically.

For role-based guards, compose a second `preHandler` after `authenticate` that reads `request.user.role`. Fastify's hook array runs sequentially, so ordering matters: verify first, authorize second.

Avoid session-based auth in Fastify unless you explicitly need server-side state — `@fastify/session` with `@fastify/cookie` works, but it fights Fastify's stateless, high-throughput design. JWTs with short expiry and a Redis-backed refresh token blocklist (checked in the `preHandler`) give you revocation without sessions.

Scope your `authenticate` hook at the plugin boundary using `fastify.register()` with `{ prefix }` to protect entire route groups without repeating the hook on every route.$escape$,
  $escape$import Fastify from 'fastify';
import jwt from '@fastify/jwt';

const app = Fastify();
await app.register(jwt, { secret: process.env.JWT_SECRET! });

app.decorate('authenticate', async (request, reply) => {
  await request.jwtVerify(); // throws 401 if invalid/expired
});

app.register(async (scope) => {
  scope.addHook('preHandler', app.authenticate);

  scope.get('/me', async (request) => {
    return { user: request.user }; // decoded JWT payload
  });

  scope.get('/admin', {
    preHandler: [app.authenticate, async (req, reply) => {
      if (req.user.role !== 'admin') reply.code(403).send({ error: 'Forbidden' });
    }],
  }, async (request) => ({ ok: true }));
}, { prefix: '/api' });$escape$,
  $escape$typescript$escape$,
