INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '8b3d8bba-59f8-43f7-bfc3-44e3a1dc38e5',
  '00000000-0000-0000-0000-000000000001',
  $escape$Fastify Input Validation — Schema-First Boundaries with Ajv$escape$,
  $escape$Fastify compiles your JSON Schema into optimized Ajv validators at startup, not per-request. Declare a schema on every route and Fastify rejects invalid payloads before your handler is ever called — zero manual validation code needed.

Attach schemas via `schema.body`, `schema.querystring`, `schema.params`, and `schema.headers`. Fastify uses `schema.response` to both validate and serialize outgoing data, stripping undeclared fields automatically — a built-in sanitization layer.

When validation fails, Fastify emits a 400 with a structured error from `setErrorHandler`. Override it to normalize shape across your API. Avoid catching validation errors inside handlers; let them bubble to the error handler so every boundary failure is handled uniformly.

Use `addSchema` + `$ref` to share schemas across routes without duplication. For string inputs that must match a pattern (emails, slugs), declare `format` or `pattern` directly in schema rather than sanitizing post-parse. Fastify's serialization also uses the response schema to fast-serialize JSON via `fast-json-stringify`, so tight schemas improve throughput as a side effect.$escape$,
  $escape$import Fastify from 'fastify';

const app = Fastify();

app.setErrorHandler((err, req, reply) => {
  if (err.validation) {
    return reply.status(400).send({ error: 'Validation failed', details: err.validation });
  }
  reply.status(500).send({ error: 'Internal server error' });
});

app.post('/users', {
  schema: {
    body: {
      type: 'object',
      required: ['email', 'age'],
      additionalProperties: false,
      properties: {
        email: { type: 'string', format: 'email' },
        age:   { type: 'integer', minimum: 13, maximum: 120 }
      }
    },
    response: {
      201: {
        type: 'object',
        properties: { id: { type: 'string' }, email: { type: 'string' } }
      }
    }
  }
}, async (req, reply) => {
  const { email, age } = req.body;
  return reply.status(201).send({ id: 'usr_123', email });
});

await app.listen({ port: 3000 });$escape$,
  $escape$javascript$escape$,
