INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'cc854543-fd13-4b80-a207-cc31ccf90369',
  '00000000-0000-0000-0000-000000000001',
  $escape$Fastify Serialization — Schema-Driven DTOs, Case Conventions, and Null Safety$escape$,
  $escape$Fastify's serialization pipeline uses `fast-json-stringify` under the hood, bypassing `JSON.stringify` entirely. Define response schemas via `schema.response` and Fastify will serialize only declared fields — undeclared properties are silently stripped, which doubles as a data-leak guard.

For camelCase responses from a snake_case DB, add a serializer transform rather than mapping in every handler. Register a custom `serializerCompiler` or use `@fastify/camelcase-keys` to coerce keys at the plugin boundary. Keep your domain objects snake_case internally; let the serialization layer own the translation.

Null handling is schema-driven: declare `{ type: ['string', 'null'] }` (JSON Schema draft-07 union syntax) to allow a field to be null. Omitting `null` from the type array causes Fastify to coerce nulls to `0` or `''` silently — a sharp edge that bites in production. For optional fields that may be absent entirely, use `{ type: 'string', nullable: true }` with the `@fastify/swagger` compatible notation, or omit the field from the schema and accept the stripping behavior intentionally.$escape$,
  $escape$import Fastify from 'fastify';

const app = Fastify();

app.get('/user/:id', {
  schema: {
    response: {
      200: {
        type: 'object',
        properties: {
          userId: { type: 'string' },
          displayName: { type: ['string', 'null'] },
          avatarUrl: { type: ['string', 'null'] },
        },
        required: ['userId'],
      },
    },
  },
}, async (req) => {
  // avatarUrl: null is preserved; undeclared fields are stripped
  return { userId: '42', displayName: null, avatarUrl: null, internalSecret: 'gone' };
});
$escape$,
  $escape$javascript$escape$,
