INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '85f3ba64-23d0-4ea7-92b1-052bfa9823aa',
  '00000000-0000-0000-0000-000000000001',
  $escape$Fastify Dev Tooling — Hot Reload, Code Generation, and Scaffolding CLI$escape$,
  $escape$Fastify's official CLI (`fastify-cli`) is the fastest path from zero to running server. `fastify generate my-app` scaffolds a project with a pre-wired plugin structure, `app.js` entry point, and `plugins/` directory following Fastify's encapsulation model — not a blank Express clone.

For hot reload during development, pair `fastify-cli` with its built-in `--watch` flag. Running `fastify start --watch src/app.js` uses `chokidar` under the hood to restart only when source files change, preserving Fastify's plugin DAG integrity on each reload.

Code generation goes further with `fastify generate plugin auth` — it emits a properly scoped plugin file with `fp()` wrapping from `fastify-plugin`, ensuring decorators registered inside don't leak scope unless you intend them to.

For monorepos or custom scaffolding, `@fastify/restartable` lets you programmatically restart a Fastify instance without killing the process — useful for test harnesses or config-driven reload in staging environments. Combine it with `fastify.inject()` to verify routes survive restarts without spinning up a real HTTP server.$escape$,
  $escape$// package.json script for hot-reload dev
// "dev": "fastify start --watch --port 3000 src/app.js"

// Generated plugin skeleton via: fastify generate plugin auth
import fp from 'fastify-plugin';
import { FastifyPluginAsync } from 'fastify';

const authPlugin: FastifyPluginAsync = async (fastify) => {
  fastify.decorate('authenticate', async (request, reply) => {
    await request.jwtVerify();
  });
};

export default fp(authPlugin, { name: 'auth' });$escape$,
  $escape$typescript$escape$,
