INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '0fe316a7-a0f1-4d32-933b-a37d0ca8ab07',
  '00000000-0000-0000-0000-000000000001',
  $escape$Fastify Monitoring — Health Checks, Prometheus Metrics, and Distributed Tracing$escape$,
  $escape$Fastify's plugin ecosystem covers the full observability stack with minimal boilerplate. For health checks, `@fastify/under-pressure` automatically monitors event loop lag, heap usage, and RSS memory, exposing a `/health` endpoint that returns `503` when thresholds are breached — no manual polling required. Pair it with `fastify-metrics` to mount a `/metrics` endpoint that exports Prometheus-compatible data including default Node.js metrics and any custom counters you register via the bundled `prom-client` instance. For distributed tracing, `@opentelemetry/instrumentation-fastify` hooks into Fastify's request lifecycle via its `onRequest` and `onResponse` hooks under the hood, automatically propagating W3C `traceparent` headers and creating spans per route. You get trace context on `request.span` without manual instrumentation. The key insight: all three plugins attach to the same Fastify instance and share its lifecycle — register them before `fastify.listen()` and they inherit your existing route prefix and `onError` hooks. Use `fastify.addHook('onClose', ...)` to flush OTel spans on graceful shutdown.$escape$,
  $escape$import Fastify from 'fastify';
import underPressure from '@fastify/under-pressure';
import metrics from 'fastify-metrics';
import { FastifyInstrumentation } from '@opentelemetry/instrumentation-fastify';

const app = Fastify({ logger: true });

await app.register(underPressure, {
  maxEventLoopDelay: 1000,
  maxHeapUsedBytes: 100_000_000,
  healthCheck: async () => ({ status: 'ok', timestamp: Date.now() }),
  healthCheckInterval: 5000,
});

await app.register(metrics, { endpoint: '/metrics' });

// OTel instrumentation — initialize before registering routes
new FastifyInstrumentation().enable();

await app.listen({ port: 3000 });$escape$,
  $escape$javascript$escape$,
